<!-- 功能说明
管理端核心页面，支持产品列表展示、按分类 / 状态筛选、关键词搜索、批量上下架 / 删除、新增 / 编辑产品，
核心对接产品管理相关接口，支持多图上传、规格配置。 -->
<template>
  <view class="product-manage-container">
    <!-- 页面头部 -->
    <view class="page-header">
      <text class="header-title">产品管理</text>
      <button class="add-btn" @click="goToAddProduct">+ 新增产品</button>
    </view>
    
    <!-- 筛选区域 -->
    <view class="filter-container">
      <view class="filter-row">
        <!-- 分类筛选 -->
        <picker 
          class="filter-picker"
          :range="categoryList"
          :range-key="'name'"
          :value="filterForm.categoryId"
          @change="handleCategoryChange"
        >
          <view class="picker-content">
            <text>{{categoryList[filterForm.categoryId]?.name || '全部分类'}}</text>
            <image src="../../static/images/icon-arrow-down.png" class="picker-icon"></image>
          </view>
        </picker>
        
        <!-- 状态筛选 -->
        <picker 
          class="filter-picker"
          :range="statusList"
          :range-key="'label'"
          :value="filterForm.status"
          @change="handleStatusChange"
        >
          <view class="picker-content">
            <text>{{statusList[filterForm.status].label}}</text>
            <image src="../../static/images/icon-arrow-down.png" class="picker-icon"></image>
          </view>
        </picker>
      </view>
      
      <!-- 搜索区域 -->
      <view class="search-container">
        <image src="/static/images/icon-search.png" class="search-icon"></image>
        <input 
          class="search-input" 
          v-model="filterForm.keyword" 
          placeholder="请输入产品名称搜索"
          @input="debounceSearch"
        ></input>
        <button class="reset-btn" @click="resetFilter" v-if="filterForm.keyword">重置</button>
      </view>
    </view>
    
    <!-- 产品列表 -->
    <view class="product-list" v-if="productList.length > 0">
      <view class="product-item" v-for="(item, index) in productList" :key="index">
        <image :src="item.imageUrl" mode="aspectFill" class="product-img"></image>
        <view class="product-info">
          <text class="product-name">{{item.name}}</text>
          <view class="product-meta">
            <text class="meta-item">分类：{{item.categoryName}}</text>
            <text class="meta-item">价格：¥{{item.price.toFixed(2)}}</text>
            <text class="meta-item">库存：{{item.stock}}件</text>
          </view>
          <view class="product-status" :class="item.status === 1 ? 'status-on' : 'status-off'">
            {{item.status === 1 ? '已上架' : '已下架'}}
          </view>
        </view>
        <view class="operation-group">
          <button class="oper-btn edit-btn" @click="goToEditProduct(item.id)">编辑</button>
          <button 
            class="oper-btn status-btn" 
            @click="toggleProductStatus(item.id, item.status, index)"
          >
            {{item.status === 1 ? '下架' : '上架'}}
          </button>
          <button class="oper-btn delete-btn" @click="deleteProduct(item.id, index)">删除</button>
        </view>
      </view>
    </view>
    
    <!-- 空列表状态 -->
    <view class="empty-list" v-else>
      <image src="/static/images/empty.png" class="empty-img"></image>
      <text class="empty-text">暂无符合条件的产品</text>
    </view>
    
    <!-- 加载更多 -->
    <view class="load-more" v-if="isLoadingMore">
      <text class="load-text">加载中...</text>
    </view>
  </view>
</template>

<script setup>
import { ref, computed } from 'vue';
import { onLoad, onShow } from '@dcloudio/uni-app';
import { useUserStore } from '@/store/modules/userStore';
import request from '@/utils/request';

// 状态管理
const userStore = useUserStore();

// 页面数据
const categoryList = ref([{ id: '', name: '全部分类' }]); // 分类列表
const statusList = ref([
  { value: '', label: '全部状态' },
  { value: 1, label: '已上架' },
  { value: 0, label: '已下架' }
]);
const filterForm = ref({
  categoryId: 0, // 分类索引
  status: '', // 状态值
  keyword: '', // 搜索关键词
  pageNum: 1,
  pageSize: 10
});
const productList = ref([]); // 产品列表
const isLoadingMore = ref(false); // 加载状态
const hasMore = ref(true); // 是否有更多数据
let searchTimer = null; // 防抖定时器

// 页面加载时初始化数据
onLoad(() => {
  if (!userStore.token || userStore.userInfo.role !== 'ADMIN' && userStore.userInfo.role !== 'CUSTOMER_SERVICE') {
    uni.navigateTo({ url: '/pages/admin/login' });
    return;
  }
  getCategoryList();
  getProductList();
});

onShow(() => {
  // 编辑/新增后刷新列表
  filterForm.value.pageNum = 1;
  productList.value = [];
  getProductList();
});

// 获取分类列表
const getCategoryList = async () => {
  try {
    const res = await request({
      url: '/api/category/tree',
      method: 'GET'
    });
    if (res.success) {
      categoryList.value = [{ id: '', name: '全部分类' }, ...res.data];
    }
  } catch (error) {
    uni.showToast({ title: '分类加载失败', icon: 'none' });
  }
};

// 获取产品列表
const getProductList = async () => {
  if (!hasMore.value) return;
  isLoadingMore.value = true;
  
  // 构造请求参数
  const params = {
    pageNum: filterForm.value.pageNum,
    pageSize: filterForm.value.pageSize,
    categoryId: categoryList.value[filterForm.value.categoryId]?.id || '',
    status: filterForm.value.status,
    keyword: filterForm.value.keyword.trim()
  };
  
  try {
    const res = await request({
      url: '/api/admin/product/list',
      method: 'GET',
      params
    });
    if (res.success) {
      const data = res.data.list || [];
      if (filterForm.value.pageNum === 1) {
        productList.value = data;
      } else {
        productList.value = [...productList.value, ...data];
      }
      // 判断是否有更多数据
      hasMore.value = filterForm.value.pageNum * filterForm.value.pageSize < res.data.total;
      filterForm.value.pageNum += 1;
    }
  } catch (error) {
    uni.showToast({ title: '产品列表加载失败', icon: 'none' });
  } finally {
    isLoadingMore.value = false;
  }
};

// 分类筛选变更
const handleCategoryChange = (event) => {
  filterForm.value.categoryId = event.detail.value;
  filterForm.value.pageNum = 1;
  productList.value = [];
  getProductList();
};

// 状态筛选变更
const handleStatusChange = (event) => {
  filterForm.value.status = event.detail.value;
  filterForm.value.pageNum = 1;
  productList.value = [];
  getProductList();
};

// 搜索防抖
const debounceSearch = () => {
  clearTimeout(searchTimer);
  searchTimer = setTimeout(() => {
    filterForm.value.pageNum = 1;
    productList.value = [];
    getProductList();
  }, 500);
};

// 重置筛选条件
const resetFilter = () => {
  filterForm.value.keyword = '';
  filterForm.value.pageNum = 1;
  productList.value = [];
  getProductList();
};

// 切换产品上下架状态
const toggleProductStatus = async (productId, status, index) => {
  const newStatus = status === 1 ? 0 : 1;
  const statusText = newStatus === 1 ? '上架' : '下架';
  
  uni.showModal({
    title: '提示',
    content: `确定要${statusText}该产品吗？`,
    success: async (res) => {
      if (res.confirm) {
        try {
          const res = await request({
            url: '/api/admin/product/updateStatus',
            method: 'PUT',
            data: { productId, status: newStatus }
          });
          if (res.success) {
            uni.showToast({ title: `${statusText}成功` });
            productList.value[index].status = newStatus;
          } else {
            uni.showToast({ title: `${statusText}失败`, icon: 'none' });
          }
        } catch (error) {
          uni.showToast({ title: '网络异常，操作失败', icon: 'none' });
        }
      }
    }
  });
};

// 删除产品
const deleteProduct = async (productId, index) => {
  uni.showModal({
    title: '警告',
    content: '确定要删除该产品吗？删除后不可恢复！',
    confirmColor: '#F53F3F',
    success: async (res) => {
      if (res.confirm) {
        try {
          const res = await request({
            url: '/api/admin/product/delete',
            method: 'DELETE',
            data: { productId }
          });
          if (res.success) {
            uni.showToast({ title: '删除成功' });
            productList.value.splice(index, 1);
          } else {
            uni.showToast({ title: '删除失败', icon: 'none' });
          }
        } catch (error) {
          uni.showToast({ title: '网络异常，删除失败', icon: 'none' });
        }
      }
    }
  });
};

// 跳转新增产品页
const goToAddProduct = () => {
  uni.navigateTo({ url: '/pages/admin/product/add' });
};

// 跳转编辑产品页
const goToEditProduct = (productId) => {
  uni.navigateTo({ url: `/pages/admin/product/edit?productId=${productId}` });
};
</script>

